/* hello.c — deliberately vulnerable */
#include <string.h>
#include <stdlib.h>
#include <stdio.h>

int main(int argc, char **argv) {
   char buff[150];          /* fixed-size stack buffer */
   printf("What is your handle?\n");
   gets(buff);              /* NO BOUNDS CHECK — classic vuln */
   printf("Wake up, %s\n", buff);
   return 0;
